#include "rsbench.cuh"
#include <thrust/device_vector.h>
#include <thrust/sort.h>
#include <thrust/functional.h>
#include <thrust/execution_policy.h>
#include <thrust/iterator/zip_iterator.h>
#include <thrust/tuple.h>

struct MatEnergyComparator
{
	__host__ __device__
	bool operator()(const thrust::tuple<int, double>& a, const thrust::tuple<int, double>& b) const
	{
		// Sort by mat ascending, then energy ascending
		if (thrust::get<0>(a) < thrust::get<0>(b)) return true;
		if (thrust::get<0>(a) > thrust::get<0>(b)) return false;
		return thrust::get<1>(a) < thrust::get<1>(b);
	}
};

__global__ void xs_lookup_kernel_optimization1(const Input in, SimulationData GSD, const int offset, const int n_samples, unsigned long long* verification)
{
	int i = blockIdx.x * blockDim.x + threadIdx.x;
	if (i >= n_samples) return;

	int idx = offset + i;

	double E = GSD.p_energy_samples[idx];
	int mat = GSD.mat_samples[idx];

	double macro_xs_vector[4] = { 0.0, 0.0, 0.0, 0.0 };

	calculate_macro_xs(macro_xs_vector, mat, E, in, GSD.num_nucs, GSD.mats, GSD.max_num_nucs, GSD.concs, GSD.n_windows, GSD.pseudo_K0RS, GSD.windows, GSD.poles, GSD.max_num_windows, GSD.max_num_poles);

	double max = -DBL_MAX;
	int max_idx = 0;
	for (int j = 0; j < 4; j++)
	{
		if (macro_xs_vector[j] > max)
		{
			max = macro_xs_vector[j];
			max_idx = j;
		}
	}

	atomicAdd(verification, (unsigned long long)(max_idx + 1));
}

void run_event_based_simulation_optimization_1(Input in, SimulationData SD, unsigned long* vhash_result)
{
	const char* optimization_name = "Optimization 1 - Kernel splitting + full material & energy sort";

	printf("Simulation Kernel:\"%s\"\n", optimization_name);

	printf("Allocating additional data required by optimized kernel...\n");
	size_t sz;
	size_t total_sz = 0;
	double start, stop;
	int i, m;

	sz = in.lookups * sizeof(double);
	SD.p_energy_samples = (double*)malloc(sz);
	total_sz += sz;
	SD.length_p_energy_samples = in.lookups;

	sz = in.lookups * sizeof(int);
	SD.mat_samples = (int*)malloc(sz);
	total_sz += sz;
	SD.length_mat_samples = in.lookups;

	printf("Allocated an additional %.0lf MB of data on CPU.\n", total_sz / 1024.0 / 1024.0);

	printf("Sampling event data...\n");
	#pragma omp parallel for schedule(dynamic, 1000)
	for (i = 0; i < in.lookups; i++)
	{
		uint64_t seed = STARTING_SEED;

		seed = fast_forward_LCG(seed, 2 * i);

		double p_energy = LCG_random_double(&seed);
		int mat = pick_mat(&seed);

		SD.p_energy_samples[i] = p_energy;
		SD.mat_samples[i] = mat;
	}
	printf("Finished sampling.\n");

	start = get_time();

	// Copy sampling arrays to device vectors for sorting
	thrust::device_vector<int> d_mat_samples(SD.mat_samples, SD.mat_samples + in.lookups);
	thrust::device_vector<double> d_p_energy_samples(SD.p_energy_samples, SD.p_energy_samples + in.lookups);

	// Zip iterators for simultaneous sort by mat then energy
	auto begin = thrust::make_zip_iterator(thrust::make_tuple(d_mat_samples.begin(), d_p_energy_samples.begin()));
	auto end = thrust::make_zip_iterator(thrust::make_tuple(d_mat_samples.end(), d_p_energy_samples.end()));

	// Sort by material ascending, then energy ascending using custom comparator
	thrust::sort(thrust::device, begin, end, MatEnergyComparator());

	stop = get_time();
	printf("Material and energy sort took %.3lf seconds\n", stop - start);

	// Copy sorted data back to host arrays
	thrust::copy(d_mat_samples.begin(), d_mat_samples.end(), SD.mat_samples);
	thrust::copy(d_p_energy_samples.begin(), d_p_energy_samples.end(), SD.p_energy_samples);

	start = get_time();

	int num_samples_per_mat[12] = { 0 };
	for (int l = 0; l < in.lookups; l++)
		num_samples_per_mat[SD.mat_samples[l]]++;

	int offsets[12] = { 0 };
	for (int m = 1; m < 12; m++)
		offsets[m] = offsets[m - 1] + num_samples_per_mat[m - 1];

	stop = get_time();
	printf("Counting samples and offsets took %.3lf seconds\n", stop - start);
	start = stop;

	unsigned long long verification = 0ULL;
	unsigned long long* d_verification;
	cudaMalloc((void**)&d_verification, sizeof(unsigned long long));
	cudaMemset(d_verification, 0, sizeof(unsigned long long));

	for (m = 0; m < 12; m++)
	{
		if (num_samples_per_mat[m] == 0) continue;

		int n_samples = num_samples_per_mat[m];
		int offset = offsets[m];

		int threadsPerBlock = 256;
		int blocksPerGrid = (n_samples + threadsPerBlock - 1) / threadsPerBlock;

		xs_lookup_kernel_optimization1<<<blocksPerGrid, threadsPerBlock>>>(in, SD, offset, n_samples, d_verification);
		cudaDeviceSynchronize();
	}

	cudaMemcpy(&verification, d_verification, sizeof(unsigned long long), cudaMemcpyDeviceToHost);
	cudaFree(d_verification);

	stop = get_time();
	printf("XS Lookups took %.3lf seconds\n", stop - start);

	*vhash_result = (unsigned long)verification;

	// Free temporary host allocations
	free(SD.p_energy_samples);
	free(SD.mat_samples);
}
